18582   /// Checks if instruction is associative and can be vectorized.
18583   static bool isVectorizable(RecurKind Kind, Instruction *I) {
18584     if (Kind == RecurKind::None)
18585       return false;
18586 
18587     // Integer ops that map to select instructions or intrinsics are fine.
18588     if (RecurrenceDescriptor::isIntMinMaxRecurrenceKind(Kind) ||
18589         isBoolLogicOp(I))
18590       return true;
18591 
18592     if (Kind == RecurKind::FMax || Kind == RecurKind::FMin) {
18593       // FP min/max are associative except for NaN and -0.0. We do not
18594       // have to rule out -0.0 here because the intrinsic semantics do not
18595       // specify a fixed result for it.
18596       return I->getFastMathFlags().noNaNs();
18597     }
18598 
18599     if (Kind == RecurKind::FMaximum || Kind == RecurKind::FMinimum)
18600       return true;
18601 
18602     return I->isAssociative();
18603   }
