18615   /// Creates reduction operation with the current opcode.
18616   static Value *createOp(IRBuilderBase &Builder, RecurKind Kind, Value *LHS,
18617                          Value *RHS, const Twine &Name, bool UseSelect) {
18618     unsigned RdxOpcode = RecurrenceDescriptor::getOpcode(Kind);
18619     switch (Kind) {
18620     case RecurKind::Or:
18621       if (UseSelect &&
18622           LHS->getType() == CmpInst::makeCmpResultType(LHS->getType()))
18623         return Builder.CreateSelect(LHS, Builder.getTrue(), RHS, Name);
18624       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
18625                                  Name);
18626     case RecurKind::And:
18627       if (UseSelect &&
18628           LHS->getType() == CmpInst::makeCmpResultType(LHS->getType()))
18629         return Builder.CreateSelect(LHS, RHS, Builder.getFalse(), Name);
18630       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
18631                                  Name);
18632     case RecurKind::Add:
18633     case RecurKind::Mul:
18634     case RecurKind::Xor:
18635     case RecurKind::FAdd:
18636     case RecurKind::FMul:
18637       return Builder.CreateBinOp((Instruction::BinaryOps)RdxOpcode, LHS, RHS,
18638                                  Name);
18639     case RecurKind::FMax:
18640       return Builder.CreateBinaryIntrinsic(Intrinsic::maxnum, LHS, RHS);
18641     case RecurKind::FMin:
18642       return Builder.CreateBinaryIntrinsic(Intrinsic::minnum, LHS, RHS);
18643     case RecurKind::FMaximum:
18644       return Builder.CreateBinaryIntrinsic(Intrinsic::maximum, LHS, RHS);
18645     case RecurKind::FMinimum:
18646       return Builder.CreateBinaryIntrinsic(Intrinsic::minimum, LHS, RHS);
18647     case RecurKind::SMax:
18648       if (UseSelect) {
18649         Value *Cmp = Builder.CreateICmpSGT(LHS, RHS, Name);
18650         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
18651       }
18652       return Builder.CreateBinaryIntrinsic(Intrinsic::smax, LHS, RHS);
18653     case RecurKind::SMin:
18654       if (UseSelect) {
18655         Value *Cmp = Builder.CreateICmpSLT(LHS, RHS, Name);
18656         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
18657       }
18658       return Builder.CreateBinaryIntrinsic(Intrinsic::smin, LHS, RHS);
18659     case RecurKind::UMax:
18660       if (UseSelect) {
18661         Value *Cmp = Builder.CreateICmpUGT(LHS, RHS, Name);
18662         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
18663       }
18664       return Builder.CreateBinaryIntrinsic(Intrinsic::umax, LHS, RHS);
18665     case RecurKind::UMin:
18666       if (UseSelect) {
18667         Value *Cmp = Builder.CreateICmpULT(LHS, RHS, Name);
18668         return Builder.CreateSelect(Cmp, LHS, RHS, Name);
18669       }
18670       return Builder.CreateBinaryIntrinsic(Intrinsic::umin, LHS, RHS);
18671     default:
18672       llvm_unreachable("Unknown reduction operation.");
18673     }
18674   }
