18678   static Value *createOp(IRBuilderBase &Builder, RecurKind RdxKind, Value *LHS,
18679                          Value *RHS, const Twine &Name,
18680                          const ReductionOpsListType &ReductionOps) {
18681     bool UseSelect = ReductionOps.size() == 2 ||
18682                      // Logical or/and.
18683                      (ReductionOps.size() == 1 &&
18684                       any_of(ReductionOps.front(), IsaPred<SelectInst>));
18685     assert((!UseSelect || ReductionOps.size() != 2 ||
18686             isa<SelectInst>(ReductionOps[1][0])) &&
18687            "Expected cmp + select pairs for reduction");
18688     Value *Op = createOp(Builder, RdxKind, LHS, RHS, Name, UseSelect);
18689     if (RecurrenceDescriptor::isIntMinMaxRecurrenceKind(RdxKind)) {
18690       if (auto *Sel = dyn_cast<SelectInst>(Op)) {
18691         propagateIRFlags(Sel->getCondition(), ReductionOps[0], nullptr,
18692                          /*IncludeWrapFlags=*/false);
18693         propagateIRFlags(Op, ReductionOps[1], nullptr,
18694                          /*IncludeWrapFlags=*/false);
18695         return Op;
18696       }
18697     }
18698     propagateIRFlags(Op, ReductionOps[0], nullptr, /*IncludeWrapFlags=*/false);
18699     return Op;
18700   }
