18703   static RecurKind getRdxKind(Value *V) {
18704     auto *I = dyn_cast<Instruction>(V);
18705     if (!I)
18706       return RecurKind::None;
18707     if (match(I, m_Add(m_Value(), m_Value())))
18708       return RecurKind::Add;
18709     if (match(I, m_Mul(m_Value(), m_Value())))
18710       return RecurKind::Mul;
18711     if (match(I, m_And(m_Value(), m_Value())) ||
18712         match(I, m_LogicalAnd(m_Value(), m_Value())))
18713       return RecurKind::And;
18714     if (match(I, m_Or(m_Value(), m_Value())) ||
18715         match(I, m_LogicalOr(m_Value(), m_Value())))
18716       return RecurKind::Or;
18717     if (match(I, m_Xor(m_Value(), m_Value())))
18718       return RecurKind::Xor;
18719     if (match(I, m_FAdd(m_Value(), m_Value())))
18720       return RecurKind::FAdd;
18721     if (match(I, m_FMul(m_Value(), m_Value())))
18722       return RecurKind::FMul;
18723 
18724     if (match(I, m_Intrinsic<Intrinsic::maxnum>(m_Value(), m_Value())))
18725       return RecurKind::FMax;
18726     if (match(I, m_Intrinsic<Intrinsic::minnum>(m_Value(), m_Value())))
18727       return RecurKind::FMin;
18728 
18729     if (match(I, m_Intrinsic<Intrinsic::maximum>(m_Value(), m_Value())))
18730       return RecurKind::FMaximum;
18731     if (match(I, m_Intrinsic<Intrinsic::minimum>(m_Value(), m_Value())))
18732       return RecurKind::FMinimum;
18733     // This matches either cmp+select or intrinsics. SLP is expected to handle
18734     // either form.
18735     // TODO: If we are canonicalizing to intrinsics, we can remove several
18736     //       special-case paths that deal with selects.
18737     if (match(I, m_SMax(m_Value(), m_Value())))
18738       return RecurKind::SMax;
18739     if (match(I, m_SMin(m_Value(), m_Value())))
18740       return RecurKind::SMin;
18741     if (match(I, m_UMax(m_Value(), m_Value())))
18742       return RecurKind::UMax;
18743     if (match(I, m_UMin(m_Value(), m_Value())))
18744       return RecurKind::UMin;
18745 
18746     if (auto *Select = dyn_cast<SelectInst>(I)) {
18747       // Try harder: look for min/max pattern based on instructions producing
18748       // same values such as: select ((cmp Inst1, Inst2), Inst1, Inst2).
18749       // During the intermediate stages of SLP, it's very common to have
18750       // pattern like this (since optimizeGatherSequence is run only once
18751       // at the end):
18752       // %1 = extractelement <2 x i32> %a, i32 0
18753       // %2 = extractelement <2 x i32> %a, i32 1
18754       // %cond = icmp sgt i32 %1, %2
18755       // %3 = extractelement <2 x i32> %a, i32 0
18756       // %4 = extractelement <2 x i32> %a, i32 1
18757       // %select = select i1 %cond, i32 %3, i32 %4
18758       CmpInst::Predicate Pred;
18759       Instruction *L1;
18760       Instruction *L2;
18761 
18762       Value *LHS = Select->getTrueValue();
18763       Value *RHS = Select->getFalseValue();
18764       Value *Cond = Select->getCondition();
18765 
18766       // TODO: Support inverse predicates.
18767       if (match(Cond, m_Cmp(Pred, m_Specific(LHS), m_Instruction(L2)))) {
18768         if (!isa<ExtractElementInst>(RHS) ||
18769             !L2->isIdenticalTo(cast<Instruction>(RHS)))
18770           return RecurKind::None;
18771       } else if (match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Specific(RHS)))) {
18772         if (!isa<ExtractElementInst>(LHS) ||
18773             !L1->isIdenticalTo(cast<Instruction>(LHS)))
18774           return RecurKind::None;
18775       } else {
18776         if (!isa<ExtractElementInst>(LHS) || !isa<ExtractElementInst>(RHS))
18777           return RecurKind::None;
18778         if (!match(Cond, m_Cmp(Pred, m_Instruction(L1), m_Instruction(L2))) ||
18779             !L1->isIdenticalTo(cast<Instruction>(LHS)) ||
18780             !L2->isIdenticalTo(cast<Instruction>(RHS)))
18781           return RecurKind::None;
18782       }
18783 
18784       switch (Pred) {
18785       default:
18786         return RecurKind::None;
18787       case CmpInst::ICMP_SGT:
18788       case CmpInst::ICMP_SGE:
18789         return RecurKind::SMax;
18790       case CmpInst::ICMP_SLT:
18791       case CmpInst::ICMP_SLE:
18792         return RecurKind::SMin;
18793       case CmpInst::ICMP_UGT:
18794       case CmpInst::ICMP_UGE:
18795         return RecurKind::UMax;
18796       case CmpInst::ICMP_ULT:
18797       case CmpInst::ICMP_ULE:
18798         return RecurKind::UMin;
18799       }
18800     }
18801     return RecurKind::None;
18802   }
