7588 static bool directlyImpliesPoison(const Value *ValAssumedPoison, const Value *V,
7589                                   unsigned Depth) {
7590   if (ValAssumedPoison == V)
7591     return true;
7592 
7593   const unsigned MaxDepth = 2;
7594   if (Depth >= MaxDepth)
7595     return false;
7596 
7597   if (const auto *I = dyn_cast<Instruction>(V)) {
7598     if (any_of(I->operands(), [=](const Use &Op) {
7599           return propagatesPoison(Op) &&
7600                  directlyImpliesPoison(ValAssumedPoison, Op, Depth + 1);
7601         }))
7602       return true;
7603 
7604     // V  = extractvalue V0, idx
7605     // V2 = extractvalue V0, idx2
7606     // V0's elements are all poison or not. (e.g., add_with_overflow)
7607     const WithOverflowInst *II;
7608     if (match(I, m_ExtractValue(m_WithOverflowInst(II))) &&
7609         (match(ValAssumedPoison, m_ExtractValue(m_Specific(II))) ||
7610          llvm::is_contained(II->args(), ValAssumedPoison)))
7611       return true;
7612   }
7613   return false;
7614 }
