7616 static bool impliesPoison(const Value *ValAssumedPoison, const Value *V,
7617                           unsigned Depth) {
7618   if (isGuaranteedNotToBePoison(ValAssumedPoison))
7619     return true;
7620 
7621   if (directlyImpliesPoison(ValAssumedPoison, V, /* Depth */ 0))
7622     return true;
7623 
7624   const unsigned MaxDepth = 2;
7625   if (Depth >= MaxDepth)
7626     return false;
7627 
7628   const auto *I = dyn_cast<Instruction>(ValAssumedPoison);
7629   if (I && !canCreatePoison(cast<Operator>(I))) {
7630     return all_of(I->operands(), [=](const Value *Op) {
7631       return impliesPoison(Op, V, Depth + 1);
7632     });
7633   }
7634   return false;
7635 }
